// src/Home.js
import React from 'react';
import "../styles/Home.css";

const Home = () => {
  return (
    <section className="hero-section">
      <div className="hero-overlay"></div>
      <div className="hero-content">
        {/* Branding & Tagline */}
        <h1 className="hero-title">
          Welcome to <span className="highlight">ProjectDuniya</span>
        </h1>
        <p className="hero-subtitle">
          A modern platform empowering students and professionals with top-tier academic and technical project solutions.
        </p>

        {/* Key Benefits */}
        <div className="hero-highlights">
          <p>🎓 500+ Projects Completed</p>
          <p>💼 100+ Clients Served</p>
          <p>⚡ 2+ Years of Excellence</p>
          <p>🚀 50% OFF on First Project + Free Resume Review</p>
        </div>

        {/* Call-To-Actions */}
        <div className="hero-buttons">
          <a href="#services" className="btn blue-btn">Explore Services</a>
          <a
            href="https://wa.me/918391808784"
            target="_blank"
            rel="noopener noreferrer"
            className="btn green-btn"
          >
            Chat on WhatsApp
          </a>
        </div>

        {/* Footer Teaser */}
        <div className="hero-footer">
          <p>
            💡 Custom Projects | ✍️ Thesis & Reports | 💻 Development & Debugging | 📊 Data Analysis
          </p>
        </div>
      </div>
    </section>
  );
};

export default Home;
